<script setup lang="ts">import AppLayout from '@/layouts/AppLayout.vue'; import { useForm } from '@inertiajs/vue3'; import { route } from 'ziggy-js'; const p=defineProps<{customer?:any;controlAccounts:any[];resultAccounts:any[]}>(); const f=useForm({name:p.customer?.name??'',document:p.customer?.document??'',receivable_account_id:p.customer?.receivable_account_id??'',default_revenue_account_id:p.customer?.default_revenue_account_id??'',active:p.customer?.active??true}); function submit(){p.customer?f.put(route('customers.update',p.customer.id)):f.post(route('customers.store'))}</script>
<template><AppLayout :title="customer?'Editar cliente':'Novo cliente'"><form class="mx-auto max-w-2xl space-y-4 p-6" @submit.prevent="submit"><h1 class="text-2xl font-bold text-white">{{ customer?'Editar cliente':'Novo cliente' }}</h1><input v-model="f.name" placeholder="Nome" class="w-full rounded bg-black p-3 text-white"><input v-model="f.document" placeholder="Documento (opcional)" class="w-full rounded bg-black p-3 text-white"><select v-model="f.receivable_account_id" class="w-full rounded bg-black p-3 text-white"><option value="">Conta de controle</option><option v-for="a in controlAccounts" :key="a.id" :value="a.id">{{a.code}} - {{a.name}}</option></select><select v-model="f.default_revenue_account_id" class="w-full rounded bg-black p-3 text-white"><option value="">Receita padrão</option><option v-for="a in resultAccounts" :key="a.id" :value="a.id">{{a.code}} - {{a.name}}</option></select><button class="rounded bg-indigo-600 px-4 py-2 text-white">Salvar cliente</button></form></AppLayout></template>
